from collections import deque
dq = deque()
for i in range(1, n+1):
    if indeg[i] == 0:
        dq.append(i)
        break

order = []
while dq:
    u = dq.popleft()
    order.append(u)
    for v in adj[u]:
        indeg[v] -= 1
        if indeg[v] == 0:
            dq.append(v)

